Javascript.miscCode:
function sendRightValue()
{
	var hrgAtt = Services.getValue(HearingAttendees.dataBinding);
	if (hrgAtt == "OTHER" || hrgAtt == "19")
	{
		return Services.getValue(OtherHearingAttendees.dataBinding);
	}
	else
	{
		var jurisdiction = Services.getValue("/ds/ManageCase/Jurisdiction");
		if ( jurisdiction == "F" )
		{
			hrgAtt = hrgAtt.replace(/JUDGMENT CREDITOR/g, "CREDITOR");
			hrgAtt = hrgAtt.replace(/JUDGMENT DEBTOR/g, "DEBTOR");
		}
		return hrgAtt.toLowerCase();
	}
}
